-- Trigger to set updated_at on UPDATE
DROP TRIGGER IF EXISTS workflow_steps_update_audit ON sapiens.workflow_steps;
CREATE TRIGGER workflow_steps_update_audit BEFORE UPDATE ON sapiens.workflow_steps
